"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

type MotionType = "symmetry" | "translation" | "rotation";

interface MotionItem {
  id: string;
  icon: string;
  name: string;
  type: MotionType;
}

const MOTION_ITEMS: MotionItem[] = [
  { id: "1", icon: "⛷️", name: "滑雪", type: "translation" },
  { id: "2", icon: "⏰", name: "钟表指针", type: "rotation" },
  { id: "3", icon: "🦋", name: "蝴蝶翅膀", type: "symmetry" },
  { id: "4", icon: "🛗", name: "电梯上下", type: "translation" },
  { id: "5", icon: "🎡", name: "摩天轮", type: "rotation" },
  { id: "6", icon: "✂️", name: "剪窗花", type: "symmetry" },
  { id: "7", icon: "🚇", name: "地铁行驶", type: "translation" },
  { id: "8", icon: "🌀", name: "电风扇", type: "rotation" },
  { id: "9", icon: "🎭", name: "京剧脸谱", type: "symmetry" },
];

const CATEGORIES: { key: MotionType; icon: string; label: string; color: string; desc: string }[] = [
  { key: "symmetry", icon: "📄", label: "轴对称", color: "var(--primary)", desc: "对折后两边完全重合" },
  { key: "translation", icon: "🚗", label: "平移", color: "var(--accent2)", desc: "沿直线移动，形状大小不变" },
  { key: "rotation", icon: "🎡", label: "旋转", color: "var(--accent)", desc: "绕着一个点或轴转动" },
];

type Phase = "intro" | "sorting" | "result";

export default function ComparePage() {
  const [phase, setPhase] = useState<Phase>("intro");
  const [sorted, setSorted] = useState<Record<MotionType, MotionItem[]>>({
    symmetry: [],
    translation: [],
    rotation: [],
  });
  const [remaining, setRemaining] = useState<MotionItem[]>(MOTION_ITEMS);
  const [draggingItem, setDraggingItem] = useState<MotionItem | null>(null);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const sortRef = useRef<HTMLDivElement | null>(null);

  const allSorted = remaining.length === 0;

  const handleDrop = (category: MotionType, item: MotionItem) => {
    if (item.type === category) {
      // 正确
      setSorted((prev) => ({ ...prev, [category]: [...prev[category], item] }));
      setRemaining((prev) => prev.filter((i) => i.id !== item.id));
    } else {
      // 错误 - 抖动提示
      const catEl = document.getElementById(`cat-${category}`);
      triggerShake(catEl);
    }
    setDraggingItem(null);
  };

  const handleDragStart = (e: React.PointerEvent, item: MotionItem) => {
    e.preventDefault();
    setDraggingItem(item);
  };

  const handleDragMove = (e: React.PointerEvent) => {
    if (!draggingItem) return;
    // 用全局事件处理
  };

  const handleDragEnd = (e: React.PointerEvent) => {
    if (!draggingItem) return;

    // 检查是否落在某个分类区域
    for (const cat of CATEGORIES) {
      const el = document.getElementById(`cat-${cat.key}`);
      if (!el) continue;
      const rect = el.getBoundingClientRect();
      if (
        e.clientX >= rect.left &&
        e.clientX <= rect.right &&
        e.clientY >= rect.top &&
        e.clientY <= rect.bottom
      ) {
        handleDrop(cat.key, draggingItem);
        return;
      }
    }

    setDraggingItem(null);
  };

  const handleTapSort = (category: MotionType, item: MotionItem) => {
    if (item.type === category) {
      setSorted((prev) => ({ ...prev, [category]: [...prev[category], item] }));
      setRemaining((prev) => prev.filter((i) => i.id !== item.id));
    } else {
      const catEl = document.getElementById(`cat-${category}`);
      triggerShake(catEl);
    }
  };

  const startSorting = () => {
    setPhase("sorting");
    // 打乱顺序
    setRemaining([...MOTION_ITEMS].sort(() => Math.random() - 0.5));
    setSorted({ symmetry: [], translation: [], rotation: [] });
  };

  return (
    <StepShell topicId="motion" stepId="compare">
      <div className="space-y-5">
        {/* 介绍阶段 */}
        {phase === "intro" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <h2 className="text-center text-xl font-bold text-[var(--text)]">
              三种运动，你分得清吗？
            </h2>
            <p className="mt-2 text-center text-sm text-[var(--text-secondary)]">
              生活中有各种各样的运动，它们可以分成三类
            </p>

            <div className="mt-6 space-y-3">
              {CATEGORIES.map((cat) => (
                <div
                  key={cat.key}
                  className="flex items-center gap-4 rounded-[var(--radius-sm)] border border-[var(--border)] bg-[var(--bg-soft)] p-4"
                >
                  <div
                    className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl text-2xl"
                    style={{ backgroundColor: cat.color, color: "white" }}
                  >
                    {cat.icon}
                  </div>
                  <div>
                    <p className="font-bold text-[var(--text)]">{cat.label}</p>
                    <p className="text-xs text-[var(--text-secondary)]">{cat.desc}</p>
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-6 flex justify-center">
              <button
                onClick={startSorting}
                className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                开始分类 →
              </button>
            </div>
          </section>
        )}

        {/* 分类阶段 */}
        {phase === "sorting" && (
          <div className="space-y-5" onPointerUp={handleDragEnd}>
            {/* 待分类的项目 */}
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <p className="text-center text-sm text-[var(--text-secondary)]">
                把下面的运动拖到对应的分类里（也可以点一下分类按钮）
              </p>
              <div className="mt-4 flex flex-wrap justify-center gap-3">
                {remaining.map((item) => (
                  <div
                    key={item.id}
                    className="flex flex-col items-center gap-1"
                  >
                    <button
                      onPointerDown={(e) => handleDragStart(e, item)}
                      className="flex h-16 w-16 cursor-grab items-center justify-center rounded-2xl bg-[var(--bg-soft)] text-3xl shadow-[var(--shadow-sm)] transition-all hover:scale-105 active:cursor-grabbing active:scale-95 touch-none"
                      title={item.name}
                    >
                      {item.icon}
                    </button>
                    <span className="text-xs text-[var(--text-secondary)]">{item.name}</span>
                  </div>
                ))}
                {remaining.length === 0 && (
                  <p className="py-4 text-sm text-[var(--text-muted)]">全部完成啦！</p>
                )}
              </div>
            </section>

            {/* 三个分类区域 */}
            <div className="space-y-3">
              {CATEGORIES.map((cat) => (
                <div
                  key={cat.key}
                  id={`cat-${cat.key}`}
                  ref={cat.key === "symmetry" ? sortRef : undefined}
                  className={`rounded-[var(--radius-sm)] border-2 border-dashed p-4 transition-all ${
                    draggingItem
                      ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/5"
                      : "border-[var(--border)] bg-[var(--bg-card)]"
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <div
                      className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl text-xl"
                      style={{ backgroundColor: cat.color, color: "white" }}
                    >
                      {cat.icon}
                    </div>
                    <div>
                      <p className="font-bold text-[var(--text)]">{cat.label}</p>
                      <p className="text-xs text-[var(--text-secondary)]">{cat.desc}</p>
                    </div>
                    <span className="ml-auto rounded-full bg-[var(--bg-soft)] px-2.5 py-0.5 text-xs text-[var(--text-muted)]">
                      {sorted[cat.key].length} 个
                    </span>
                  </div>

                  {/* 已分类的项目 */}
                  {sorted[cat.key].length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-2">
                      {sorted[cat.key].map((item) => (
                        <div
                          key={item.id}
                          className="flex flex-col items-center gap-0.5 animate-float-in"
                        >
                          <div
                            className="flex h-12 w-12 items-center justify-center rounded-xl text-2xl"
                            style={{ backgroundColor: cat.color + "30" }}
                          >
                            {item.icon}
                          </div>
                          <span className="text-[10px] text-[var(--text-secondary)]">{item.name}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* 点击分类按钮（移动端友好） */}
                  {draggingItem && (
                    <button
                      onClick={() => handleTapSort(cat.key, draggingItem)}
                      className="mt-3 w-full rounded-lg py-2 text-sm font-medium text-white transition-all"
                      style={{ backgroundColor: cat.color }}
                    >
                      放到「{cat.label}」
                    </button>
                  )}
                </div>
              ))}
            </div>

            {/* 进度 */}
            <div className="rounded-[var(--radius-sm)] bg-[var(--bg-card)]/60 p-3 text-center text-sm text-[var(--text-secondary)]">
              已分类{" "}
              <span className="font-bold text-[var(--text)]">
                {MOTION_ITEMS.length - remaining.length}
              </span>{" "}
              / {MOTION_ITEMS.length}
            </div>

            {allSorted && (
              <div className="flex justify-center">
                <button
                  onClick={() => setPhase("result")}
                  className="animate-float-in rounded-full bg-[var(--signal-success)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  看看结果 →
                </button>
              </div>
            )}
          </div>
        )}

        {/* 结果阶段 */}
        {phase === "result" && (
          <div className="space-y-5">
            <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
              <div className="text-5xl animate-bounce-soft">⚖️</div>
              <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
                {completeMsg}
              </h2>
              <p className="mt-2 text-[var(--text-secondary)]">
                你成功区分了三种运动方式！
              </p>
            </section>

            {/* 总结三种运动 */}
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h3 className="text-center font-bold text-[var(--text)]">
                三种运动的特点
              </h3>
              <div className="mt-4 space-y-3">
                {CATEGORIES.map((cat) => {
                  const items = sorted[cat.key];
                  return (
                    <div
                      key={cat.key}
                      className="rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3"
                    >
                      <div className="flex items-center gap-2">
                        <span
                          className="flex h-8 w-8 items-center justify-center rounded-lg text-lg"
                          style={{ backgroundColor: cat.color, color: "white" }}
                        >
                          {cat.icon}
                        </span>
                        <span className="font-bold text-[var(--text)]">{cat.label}</span>
                      </div>
                      <p className="mt-1 text-xs text-[var(--text-secondary)]">{cat.desc}</p>
                      <div className="mt-2 flex gap-1.5">
                        {items.map((item) => (
                          <span key={item.id} className="text-xl" title={item.name}>
                            {item.icon}
                          </span>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>

            <div className="flex flex-wrap justify-center gap-3">
              <button
                onClick={startSorting}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/motion/count"
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
              >
                下一步：数一数 →
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
